-- ----- POLICIES -----
DROP POLICY IF EXISTS "ASN lihat absensi sendiri" ON public.absensi_asn;
CREATE POLICY "ASN lihat absensi sendiri" ON public.absensi_asn AS PERMISSIVE FOR SELECT TO authenticated USING (((auth.uid() = user_id) OR has_role(auth.uid(), 'super_admin'::app_role) OR (has_role(auth.uid(), 'admin_opd'::app_role) AND (opd_id = get_user_opd(auth.uid())))));
DROP POLICY IF EXISTS "ASN tambah absensi sendiri" ON public.absensi_asn;
CREATE POLICY "ASN tambah absensi sendiri" ON public.absensi_asn AS PERMISSIVE FOR INSERT TO authenticated WITH CHECK ((auth.uid() = user_id));
DROP POLICY IF EXISTS "Super admin kelola absensi" ON public.absensi_asn;
