-- =====================  FUNCTIONS  =====================
CREATE OR REPLACE FUNCTION public._lovable_exec_sql(sql text)
 RETURNS void
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN EXECUTE sql; END; $function$;
CREATE OR REPLACE FUNCTION public._lovable_request_uid()
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COALESCE(NULLIF(current_setting('request.jwt.claim.sub', true), ''),
    NULLIF(current_setting('request.jwt.claims', true), '')::jsonb ->> 'sub')::uuid;
$function$;
CREATE OR REPLACE FUNCTION public.aset_compliance(_opd_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT jsonb_build_object(
    'total', COUNT(*)::int,
    'aktif', COUNT(*) FILTER (WHERE COALESCE(status, lifecycle_status) = 'aktif' OR lifecycle_status = 'aktif')::int,
    'rusak', COUNT(*) FILTER (WHERE status = 'rusak' OR lifecycle_status = 'rusak')::int,
    'hilang', COUNT(*) FILTER (WHERE lifecycle_status = 'hilang')::int,
    'maintenance', COUNT(*) FILTER (WHERE lifecycle_status = 'maintenance')::int,
    'terverifikasi_90d', COUNT(*) FILTER (WHERE last_verified_at >= now() - interval '90 days')::int,
    'belum_verifikasi', COUNT(*) FILTER (WHERE last_verified_at IS NULL OR last_verified_at < now() - interval '90 days')::int
  )
  FROM public.aset
  WHERE _opd_id IS NULL OR opd_id = _opd_id;
$function$;
CREATE OR REPLACE FUNCTION public.aset_due_warranty(_days integer DEFAULT 30)
 RETURNS TABLE(aset_id uuid, kode text, nama text, opd_id uuid, jenis text, due_date date)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT *
  FROM (
    SELECT a.id AS aset_id, a.kode, a.nama, a.opd_id, 'garansi'::text AS jenis, a.garansi_sampai AS due_date
    FROM public.aset a
    WHERE a.garansi_sampai IS NOT NULL
      AND a.garansi_sampai BETWEEN CURRENT_DATE AND CURRENT_DATE + GREATEST(_days, 1)
    UNION ALL
    SELECT a.id AS aset_id, a.kode, a.nama, a.opd_id, 'kalibrasi'::text AS jenis, a.kalibrasi_berikut AS due_date
    FROM public.aset a
    WHERE a.kalibrasi_berikut IS NOT NULL
      AND a.kalibrasi_berikut BETWEEN CURRENT_DATE AND CURRENT_DATE + GREATEST(_days, 1)
  ) due
  ORDER BY due.due_date ASC;
$function$;
CREATE OR REPLACE FUNCTION public.aset_set_qr_token()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public', 'extensions'
AS $function$
BEGIN
  IF NEW.qr_token IS NULL THEN
    NEW.qr_token := encode(extensions.gen_random_bytes(16), 'hex');
  END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.attendance_compliance(_user_id uuid, _from date, _to date)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH days AS (
    SELECT generate_series(_from, _to, interval '1 day')::date AS tanggal
  ), masuk AS (
    SELECT waktu::date AS tanggal, bool_or(is_late) AS is_late
    FROM public.absensi_asn
    WHERE user_id = _user_id
      AND tipe = 'masuk'
      AND waktu::date BETWEEN _from AND _to
    GROUP BY waktu::date
  )
  SELECT jsonb_build_object(
    'hari', COUNT(*)::int,
    'hadir', COUNT(m.tanggal)::int,
    'terlambat', COUNT(*) FILTER (WHERE COALESCE(m.is_late, false))::int,
    'tidak_hadir', (COUNT(*) - COUNT(m.tanggal))::int,
    'persen_hadir', CASE WHEN COUNT(*) = 0 THEN 0 ELSE ROUND(COUNT(m.tanggal)::numeric / COUNT(*)::numeric * 100, 2) END
  )
  FROM days d
  LEFT JOIN masuk m ON m.tanggal = d.tanggal;
$function$;
CREATE OR REPLACE FUNCTION public.attendance_device_alert(_days integer DEFAULT 7)
 RETURNS TABLE(device_fingerprint_hash text, user_count bigint, hit_count bigint, user_ids uuid[])
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT
    a.device_fingerprint_hash,
    COUNT(DISTINCT a.user_id)::bigint AS user_count,
    COUNT(*)::bigint AS hit_count,
    array_agg(DISTINCT a.user_id) AS user_ids
  FROM public.absensi_asn a
  WHERE a.device_fingerprint_hash IS NOT NULL
    AND a.waktu >= now() - make_interval(days => GREATEST(_days, 1))
  GROUP BY a.device_fingerprint_hash
  HAVING COUNT(DISTINCT a.user_id) > 1
  ORDER BY COUNT(DISTINCT a.user_id) DESC, COUNT(*) DESC;
$function$;
CREATE OR REPLACE FUNCTION public.attendance_rekap_bulanan(_user_id uuid, _year integer, _month integer)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH bounds AS (
    SELECT make_date(_year, _month, 1) AS d1,
           (make_date(_year, _month, 1) + interval '1 month')::date AS d2
  ), days AS (
    SELECT generate_series((SELECT d1 FROM bounds), (SELECT d2 FROM bounds) - 1, interval '1 day')::date AS tanggal
  ), masuk AS (
    SELECT waktu::date AS tanggal, bool_or(is_late) AS is_late, max(late_minutes) AS late_minutes
    FROM public.absensi_asn, bounds
    WHERE user_id = _user_id
      AND tipe = 'masuk'
      AND waktu::date >= bounds.d1
      AND waktu::date < bounds.d2
    GROUP BY waktu::date
  ), pulang AS (
    SELECT waktu::date AS tanggal
    FROM public.absensi_asn, bounds
    WHERE user_id = _user_id
      AND tipe = 'pulang'
      AND waktu::date >= bounds.d1
      AND waktu::date < bounds.d2
    GROUP BY waktu::date
  )
  SELECT jsonb_build_object(
    'year', _year,
    'month', _month,
    'hari', COUNT(*)::int,
    'hadir', COUNT(masuk.tanggal)::int,
    'pulang', COUNT(pulang.tanggal)::int,
    'terlambat', COUNT(*) FILTER (WHERE COALESCE(masuk.is_late, false))::int,
    'late_minutes', COALESCE(SUM(COALESCE(masuk.late_minutes, 0)), 0)::int,
    'tidak_hadir', (COUNT(*) - COUNT(masuk.tanggal))::int
  )
  FROM days
  LEFT JOIN masuk USING (tanggal)
  LEFT JOIN pulang USING (tanggal);
$function$;
CREATE OR REPLACE FUNCTION public.check_signed_document_status(_id uuid)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT CASE
    WHEN s.status = 'revoked' THEN 'REVOKED'
    WHEN s.expires_at IS NOT NULL AND s.expires_at < now() THEN 'EXPIRED'
    WHEN s.status = 'signed' THEN 'VALID'
    ELSE upper(s.status)
  END
  FROM public.signed_documents s
  WHERE s.id = _id;
$function$;
CREATE OR REPLACE FUNCTION public.count_permohonan_bulan_ini()
 RETURNS integer
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT COUNT(*)::int FROM public.permohonan WHERE tanggal_masuk >= date_trunc('month', now());
$function$;
CREATE OR REPLACE FUNCTION public.executive_summary()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _result jsonb;
BEGIN
  IF NOT public.is_elevated_view(auth.uid()) THEN RAISE EXCEPTION 'Forbidden'; END IF;
  SELECT jsonb_build_object(
    'permohonan', jsonb_build_object(
      'total', (SELECT COUNT(*) FROM public.permohonan),
      'baru', (SELECT COUNT(*) FROM public.permohonan WHERE status = 'baru'),
      'diproses', (SELECT COUNT(*) FROM public.permohonan WHERE status = 'diproses'),
      'selesai', (SELECT COUNT(*) FROM public.permohonan WHERE status = 'selesai'),
      'overdue', (SELECT COUNT(*) FROM public.v_permohonan_overdue)),
    'aset', jsonb_build_object(
      'total', (SELECT COUNT(*) FROM public.aset),
      'aktif', (SELECT COUNT(*) FROM public.aset WHERE status = 'aktif')),
    'pengguna', jsonb_build_object(
      'total', (SELECT COUNT(*) FROM public.profiles),
      'asn', (SELECT COUNT(*) FROM public.user_roles WHERE role = 'asn')),
    'generated_at', now()) INTO _result;
  RETURN _result;
END; $function$;
CREATE OR REPLACE FUNCTION public.fn_generate_nomor_surat(_opd_id uuid, _permohonan_id uuid)
 RETURNS text
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _tahun integer := EXTRACT(YEAR FROM now())::integer;
  _seq integer;
  _fmt text;
  _kode text;
  _singkatan text;
  _nomor text;
BEGIN
  INSERT INTO public.nomor_surat_sequence (opd_id, tahun, last_number)
  VALUES (_opd_id, _tahun, 1)
  ON CONFLICT (opd_id, tahun) DO UPDATE SET last_number = public.nomor_surat_sequence.last_number + 1, updated_at = now()
  RETURNING last_number INTO _seq;

  SELECT COALESCE(nomor_surat_format, '{kode}/{seq}/{singkatan}/{tahun}'), COALESCE(nomor_surat_kode, '470'), COALESCE(singkatan, 'OPD')
  INTO _fmt, _kode, _singkatan
  FROM public.opd WHERE id = _opd_id;

  _nomor := replace(replace(replace(replace(_fmt, '{kode}', _kode), '{seq}', lpad(_seq::text, 3, '0')), '{singkatan}', _singkatan), '{tahun}', _tahun::text);

  UPDATE public.permohonan SET nomor_surat = _nomor WHERE id = _permohonan_id;
  INSERT INTO public.nomor_surat_issued (nomor, tahun, opd_id, permohonan_id, issued_by)
  VALUES (_nomor, _tahun, _opd_id, _permohonan_id, auth.uid())
  ON CONFLICT (nomor) DO NOTHING;
  RETURN _nomor;
END;
$function$;
CREATE OR REPLACE FUNCTION public.fn_ikm_dashboard(_survey_id uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH r AS (
    SELECT * FROM public.ikm_responses WHERE survey_id = _survey_id
  ), agg AS (
    SELECT
      COUNT(*)::int AS total,
      AVG((COALESCE(u1,0)+COALESCE(u2,0)+COALESCE(u3,0)+COALESCE(u4,0)+COALESCE(u5,0)+COALESCE(u6,0)+COALESCE(u7,0)+COALESCE(u8,0)+COALESCE(u9,0))::numeric / 9.0) AS rata,
      AVG(u1)::numeric AS u1, AVG(u2)::numeric AS u2, AVG(u3)::numeric AS u3,
      AVG(u4)::numeric AS u4, AVG(u5)::numeric AS u5, AVG(u6)::numeric AS u6,
      AVG(u7)::numeric AS u7, AVG(u8)::numeric AS u8, AVG(u9)::numeric AS u9
    FROM r
  )
  SELECT jsonb_build_object(
    'total', total,
    'rata', ROUND(COALESCE(rata,0), 2),
    'nilai_ikm', ROUND(COALESCE(rata,0) * 25, 2),
    'mutu', CASE WHEN COALESCE(rata,0) >= 3.53 THEN 'A' WHEN COALESCE(rata,0) >= 3.06 THEN 'B' WHEN COALESCE(rata,0) >= 2.60 THEN 'C' ELSE 'D' END,
    'u1', ROUND(COALESCE(u1,0),2), 'u2', ROUND(COALESCE(u2,0),2), 'u3', ROUND(COALESCE(u3,0),2),
    'u4', ROUND(COALESCE(u4,0),2), 'u5', ROUND(COALESCE(u5,0),2), 'u6', ROUND(COALESCE(u6,0),2),
    'u7', ROUND(COALESCE(u7,0),2), 'u8', ROUND(COALESCE(u8,0),2), 'u9', ROUND(COALESCE(u9,0),2)
  ) FROM agg;
$function$;
CREATE OR REPLACE FUNCTION public.fn_permohonan_effective_sla_seconds(_id uuid)
 RETURNS integer
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT GREATEST(0, EXTRACT(EPOCH FROM (COALESCE(p.updated_at, now()) - p.tanggal_masuk))::integer - COALESCE(p.sla_total_pause_seconds, 0))
  FROM public.permohonan p
  WHERE p.id = _id;
$function$;
CREATE OR REPLACE FUNCTION public.fn_retention_cleanup()
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _audit int := 0; _verif int := 0; _rl int := 0; _notif int := 0;
BEGIN
  DELETE FROM public.audit_log WHERE created_at < now() - interval '365 days';
  GET DIAGNOSTICS _audit = ROW_COUNT;

  DELETE FROM public.verification_logs WHERE created_at < now() - interval '180 days';
  GET DIAGNOSTICS _verif = ROW_COUNT;

  DELETE FROM public.rate_limit_hits WHERE last_hit_at < now() - interval '7 days';
  GET DIAGNOSTICS _rl = ROW_COUNT;

  DELETE FROM public.notifications WHERE dibaca = true AND created_at < now() - interval '90 days';
  GET DIAGNOSTICS _notif = ROW_COUNT;

  RETURN jsonb_build_object('audit_log', _audit, 'verification_logs', _verif, 'rate_limit_hits', _rl, 'notifications', _notif, 'executed_at', now());
END;
$function$;
CREATE OR REPLACE FUNCTION public.fn_susut_bulanan_run(_periode text)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _inserted integer := 0;
  _eligible integer := 0;
BEGIN
  IF _periode !~ '^\d{4}-\d{2}$' THEN
    RAISE EXCEPTION 'Format periode harus YYYY-MM';
  END IF;

  WITH eligible AS (
    SELECT
      a.id AS aset_id,
      GREATEST(
        ROUND((COALESCE(a.nilai_perolehan, 0) - COALESCE(a.nilai_sisa, 0)) / GREATEST(COALESCE(a.umur_ekonomis_bulan, 0), 1), 2),
        0
      )::numeric AS susut_bulan,
      COALESCE(a.nilai_perolehan, 0)::numeric AS nilai_perolehan,
      COALESCE(a.nilai_sisa, 0)::numeric AS nilai_sisa,
      COALESCE((
        SELECT h.akumulasi
        FROM public.aset_penyusutan_history h
        WHERE h.aset_id = a.id
        ORDER BY h.periode DESC, h.created_at DESC
        LIMIT 1
      ), 0)::numeric AS akumulasi_lama
    FROM public.aset a
    WHERE COALESCE(a.nilai_perolehan, 0) > 0
      AND COALESCE(a.umur_ekonomis_bulan, 0) > 0
      AND COALESCE(a.metode_susut, 'garis_lurus') = 'garis_lurus'
      AND COALESCE(a.status, 'aktif') <> 'dihapuskan'
  ), counted AS (
    SELECT COUNT(*)::int AS total FROM eligible
  ), ins AS (
    INSERT INTO public.aset_penyusutan_history (aset_id, periode, susut_bulan, akumulasi, nilai_buku)
    SELECT
      e.aset_id,
      _periode,
      LEAST(e.susut_bulan, GREATEST(e.nilai_perolehan - e.nilai_sisa - e.akumulasi_lama, 0)),
      LEAST(e.akumulasi_lama + e.susut_bulan, GREATEST(e.nilai_perolehan - e.nilai_sisa, 0)),
      GREATEST(e.nilai_perolehan - LEAST(e.akumulasi_lama + e.susut_bulan, GREATEST(e.nilai_perolehan - e.nilai_sisa, 0)), e.nilai_sisa)
    FROM eligible e
    ON CONFLICT (aset_id, periode) DO NOTHING
    RETURNING 1
  )
  SELECT (SELECT total FROM counted), COUNT(*)::int
  INTO _eligible, _inserted
  FROM ins;

  RETURN jsonb_build_object('inserted', _inserted, 'skipped', GREATEST(_eligible - _inserted, 0), 'periode', _periode);
END;
$function$;
CREATE OR REPLACE FUNCTION public.get_effective_permissions(_user_id uuid)
 RETURNS TABLE(permission_code text, code text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT DISTINCT p.permission_code, p.permission_code
  FROM public.user_permissions p
  WHERE p.user_id = _user_id AND p.granted = true AND p.revoked_at IS NULL
    AND (p.expires_at IS NULL OR p.expires_at > now())
  UNION
  SELECT perm.code, perm.code FROM public.permissions perm
  WHERE public.has_role(_user_id,'super_admin'::public.app_role)
  UNION
  SELECT perm.code, perm.code FROM public.permissions perm
  WHERE public.has_role(_user_id,'admin_pemda'::public.app_role)
    AND (perm.code LIKE 'view_%' OR perm.code LIKE 'pemda.%' OR perm.code = 'executive.view')
  UNION
  SELECT perm.code, perm.code FROM public.permissions perm
  WHERE public.has_role(_user_id,'pimpinan'::public.app_role)
    AND (perm.code LIKE 'view_%' OR perm.code = 'executive.view')
  UNION
  SELECT perm.code, perm.code FROM public.permissions perm
  WHERE public.has_role(_user_id,'pimpinan'::public.app_role)
    AND public.is_bupati(_user_id)
    AND perm.code IN ('executive.approve','executive.sign','executive.disposition');
$function$;
CREATE OR REPLACE FUNCTION public.get_user_desa(_user_id uuid)
 RETURNS text
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$ SELECT desa FROM public.profiles WHERE id = _user_id LIMIT 1; $function$;
CREATE OR REPLACE FUNCTION public.get_user_opd(_user_id uuid)
 RETURNS uuid
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT opd_id FROM public.profiles WHERE id = _user_id LIMIT 1;
$function$;
CREATE OR REPLACE FUNCTION public.governance_inventory()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _uid uuid := auth.uid();
  _result jsonb;
BEGIN
  IF _uid IS NULL OR NOT (
    public.has_role(_uid, 'super_admin') OR public.has_role(_uid, 'admin_pemda')
  ) THEN
    RAISE EXCEPTION 'forbidden';
  END IF;
  SELECT jsonb_build_object(
    'nomor_surat_total', (SELECT COUNT(*) FROM public.nomor_surat_issued),
    'nomor_surat_tahun_ini', (SELECT COUNT(*) FROM public.nomor_surat_issued WHERE tahun = EXTRACT(YEAR FROM now())::int),
    'share_paket_aktif', (SELECT COUNT(*) FROM public.share_paket WHERE status IS DISTINCT FROM 'dibatalkan'),
    'verification_logs_30d', (SELECT COUNT(*) FROM public.verification_logs WHERE created_at > now() - interval '30 days'),
    'data_request_pending', (SELECT COUNT(*) FROM public.data_requests WHERE status IN ('baru','review')),
    'legacy_submission_total', (SELECT COUNT(*) FROM public.submissions),
    'legacy_submission_unmigrated', (SELECT COUNT(*) FROM public.submissions s
       WHERE NOT EXISTS (SELECT 1 FROM public.form_submissions fs WHERE fs.legacy_submission_id = s.id)),
    'dataset_template_total', (SELECT COUNT(*) FROM public.dataset_template),
    'dataset_template_aktif', (SELECT COUNT(*) FROM public.dataset_template WHERE aktif),
    'unit_kerja_total', (SELECT COUNT(*) FROM public.unit_kerja),
    'rate_limit_hits_24h', (SELECT COUNT(*) FROM public.rate_limit_hits WHERE last_hit_at > now() - interval '24 hours')
  ) INTO _result;
  RETURN _result;
EXCEPTION WHEN undefined_column THEN
  -- legacy_submission_id belum ada di form_submissions: fallback tanpa hubungan migrasi
  SELECT jsonb_build_object(
    'nomor_surat_total', (SELECT COUNT(*) FROM public.nomor_surat_issued),
    'nomor_surat_tahun_ini', (SELECT COUNT(*) FROM public.nomor_surat_issued WHERE tahun = EXTRACT(YEAR FROM now())::int),
    'share_paket_aktif', (SELECT COUNT(*) FROM public.share_paket),
    'verification_logs_30d', (SELECT COUNT(*) FROM public.verification_logs WHERE created_at > now() - interval '30 days'),
    'data_request_pending', (SELECT COUNT(*) FROM public.data_requests),
    'legacy_submission_total', (SELECT COUNT(*) FROM public.submissions),
    'legacy_submission_unmigrated', (SELECT COUNT(*) FROM public.submissions),
    'dataset_template_total', (SELECT COUNT(*) FROM public.dataset_template),
    'dataset_template_aktif', (SELECT COUNT(*) FROM public.dataset_template WHERE aktif),
    'unit_kerja_total', (SELECT COUNT(*) FROM public.unit_kerja),
    'rate_limit_hits_24h', (SELECT COUNT(*) FROM public.rate_limit_hits WHERE last_hit_at > now() - interval '24 hours')
  ) INTO _result;
  RETURN _result;
END $function$;
CREATE OR REPLACE FUNCTION public.governance_summary()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _result jsonb;
BEGIN
  IF NOT public.is_elevated_view(auth.uid()) THEN RAISE EXCEPTION 'Forbidden'; END IF;
  SELECT jsonb_build_object(
    'compliance', jsonb_build_object(
      'total', (SELECT COUNT(*) FROM public.compliance_checklist),
      'done', (SELECT COUNT(*) FROM public.compliance_checklist WHERE status = 'done'),
      'in_progress', (SELECT COUNT(*) FROM public.compliance_checklist WHERE status = 'in_progress'),
      'todo', (SELECT COUNT(*) FROM public.compliance_checklist WHERE status = 'todo')),
    'dead_letters', jsonb_build_object(
      'unresolved', (SELECT COUNT(*) FROM public.dead_letter_jobs WHERE resolved_at IS NULL),
      'total', (SELECT COUNT(*) FROM public.dead_letter_jobs)),
    'retry_queue', jsonb_build_object(
      'pending', (SELECT COUNT(*) FROM public.retry_queue WHERE status = 'pending'),
      'retrying', (SELECT COUNT(*) FROM public.retry_queue WHERE status = 'retrying'),
      'dead', (SELECT COUNT(*) FROM public.retry_queue WHERE status = 'dead_letter')),
    'generated_at', now()) INTO _result;
  RETURN _result;
END; $function$;
CREATE OR REPLACE FUNCTION public.handle_new_user()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  INSERT INTO public.profiles (id, nama_lengkap, no_hp, nik, desa) VALUES (
    NEW.id,
    COALESCE(NEW.raw_user_meta_data->>'nama_lengkap', ''),
    NEW.raw_user_meta_data->>'no_hp',
    NEW.raw_user_meta_data->>'nik',
    NEW.raw_user_meta_data->>'desa'
  );
  INSERT INTO public.user_roles (user_id, role) VALUES (NEW.id, 'warga') ON CONFLICT DO NOTHING;
  RETURN NEW;
END; $function$;
CREATE OR REPLACE FUNCTION public.has_permission(_user_id uuid, _permission_code text)
 RETURNS boolean
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _ok boolean;
BEGIN
  SELECT EXISTS (
    SELECT 1 FROM public.user_permissions up
    WHERE up.user_id = _user_id AND up.permission_code = _permission_code
      AND up.granted = true AND up.revoked_at IS NULL
      AND (up.expires_at IS NULL OR up.expires_at > now())
  ) INTO _ok;
  IF _ok THEN RETURN true; END IF;

  IF public.has_role(_user_id,'super_admin'::app_role) THEN RETURN true; END IF;

  IF public.has_role(_user_id,'admin_pemda'::app_role) THEN
    IF _permission_code LIKE 'view_%' OR _permission_code LIKE 'pemda.%'
       OR _permission_code = 'executive.view' THEN RETURN true; END IF;
  END IF;

  IF public.has_role(_user_id,'pimpinan'::app_role) THEN
    IF _permission_code LIKE 'view_%' OR _permission_code = 'executive.view' THEN RETURN true; END IF;
    IF public.is_bupati(_user_id)
       AND _permission_code IN ('executive.approve','executive.sign','executive.disposition')
    THEN RETURN true; END IF;
  END IF;

  RETURN false;
END;
$function$;
CREATE OR REPLACE FUNCTION public.has_role(_user_id uuid, _role app_role)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (SELECT 1 FROM public.user_roles WHERE user_id = _user_id AND role = _role)
$function$;
CREATE OR REPLACE FUNCTION public.is_admin_pemda(_uid uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT public.has_role(_uid,'super_admin'::app_role) OR public.has_role(_uid,'admin_pemda'::app_role);
$function$;
CREATE OR REPLACE FUNCTION public.is_bupati(_uid uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT EXISTS (
    SELECT 1 FROM public.pejabat
    WHERE user_id = _uid
      AND COALESCE(aktif, true) = true
      AND pimpinan_type = 'bupati'
  );
$function$;
CREATE OR REPLACE FUNCTION public.is_elevated_view(_uid uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT public.has_role(_uid,'super_admin'::app_role)
      OR public.has_role(_uid,'admin_pemda'::app_role)
      OR public.has_role(_uid,'pimpinan'::app_role);
$function$;
CREATE OR REPLACE FUNCTION public.is_executive(_uid uuid)
 RETURNS boolean
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT public.has_role(_uid,'super_admin'::app_role)
