CREATE OR REPLACE FUNCTION public.layanan_kinerja_agg()
 RETURNS TABLE(layanan_id uuid, layanan_judul text, opd_id uuid, opd_singkatan text, kategori text, total bigint, selesai bigint, on_time bigint, selesai_dengan_sla bigint, rata_hari_selesai numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT NULL::uuid, p.kategori, p.opd_id, o.singkatan, p.kategori,
    COUNT(*)::bigint, COUNT(*) FILTER (WHERE p.status='selesai')::bigint,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL AND p.updated_at <= p.tenggat)::bigint,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL)::bigint,
    ROUND(AVG(EXTRACT(EPOCH FROM (p.updated_at - p.tanggal_masuk))/86400.0) FILTER (WHERE p.status='selesai')::numeric, 2)
  FROM public.permohonan p LEFT JOIN public.opd o ON o.id = p.opd_id
  GROUP BY p.kategori, p.opd_id, o.singkatan ORDER BY 6 DESC;
$function$;
CREATE OR REPLACE FUNCTION public.log_permohonan_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF TG_OP='UPDATE' AND OLD.status IS DISTINCT FROM NEW.status THEN
    INSERT INTO public.audit_log (user_id, aksi, entitas, entitas_id, data_sebelum, data_sesudah)
    VALUES (auth.uid(),'permohonan.status_changed','permohonan',NEW.id::text,
      jsonb_build_object('status',OLD.status), jsonb_build_object('status',NEW.status));
  END IF;
  RETURN NEW;
END; $function$;
CREATE OR REPLACE FUNCTION public.migrasi_dataset_ke_forms(_template_id uuid)
 RETURNS uuid
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  t record;
  f_id uuid;
  k jsonb;
  idx integer := 0;
BEGIN
  SELECT * INTO t FROM public.dataset_template WHERE id = _template_id;
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Template tidak ditemukan';
  END IF;

  INSERT INTO public.forms (judul, deskripsi, opd_pemilik_id, deadline, allow_multiple_submit, status, created_by)
  VALUES (t.judul, t.deskripsi, COALESCE(t.opd_pemilik_id, t.opd_id), t.deadline, COALESCE(t.allow_multiple_submit, false), 'draft', t.created_by)
  RETURNING id INTO f_id;

  FOR k IN SELECT * FROM jsonb_array_elements(COALESCE(t.kolom, '[]'::jsonb)) LOOP
    INSERT INTO public.form_fields (form_id, kode, label, tipe, required, help, help_text, options, urutan)
    VALUES (
      f_id,
      COALESCE(k->>'key', 'field_' || idx),
      COALESCE(k->>'label', k->>'key', 'Field ' || idx),
      COALESCE(k->>'tipe', 'short_text'),
      COALESCE((k->>'required')::boolean, false),
      k->>'help',
      k->>'help',
      COALESCE(k->'options', '[]'::jsonb),
      idx
    );
    idx := idx + 1;
  END LOOP;

  UPDATE public.dataset_template SET aktif = false WHERE id = _template_id;
  RETURN f_id;
END;
$function$;
CREATE OR REPLACE FUNCTION public.opd_attendance_today(_opd_id uuid DEFAULT NULL::uuid)
 RETURNS jsonb
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH asn AS (
    SELECT p.id
    FROM public.profiles p
    WHERE (_opd_id IS NULL OR p.opd_id = _opd_id)
      AND EXISTS (SELECT 1 FROM public.user_roles ur WHERE ur.user_id = p.id AND ur.role = 'asn')
  ), masuk AS (
    SELECT DISTINCT ON (a.user_id) a.user_id, a.is_late
    FROM public.absensi_asn a
    WHERE a.tipe = 'masuk'
      AND a.waktu >= date_trunc('day', now())
      AND a.waktu < date_trunc('day', now()) + interval '1 day'
      AND (_opd_id IS NULL OR a.opd_id = _opd_id)
    ORDER BY a.user_id, a.waktu ASC
  )
  SELECT jsonb_build_object(
    'total_asn', COUNT(asn.id)::int,
    'hadir', COUNT(masuk.user_id)::int,
    'terlambat', COUNT(*) FILTER (WHERE COALESCE(masuk.is_late, false))::int,
    'belum_hadir', GREATEST(COUNT(asn.id) - COUNT(masuk.user_id), 0)::int
  )
  FROM asn
  LEFT JOIN masuk ON masuk.user_id = asn.id;
$function$;
CREATE OR REPLACE FUNCTION public.opd_kategori_benchmark(_kategori text)
 RETURNS TABLE(opd_id uuid, opd_nama text, opd_singkatan text, total bigint, selesai bigint, sla_pct numeric, rating_avg numeric, skor numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH p AS (
    SELECT * FROM public.permohonan WHERE kategori = _kategori
  ), agg AS (
    SELECT opd_id,
      COUNT(*)::bigint AS total,
      COUNT(*) FILTER (WHERE status='selesai')::numeric AS selesai,
      COUNT(*) FILTER (WHERE status='selesai' AND tenggat IS NOT NULL AND updated_at <= tenggat)::numeric AS on_time,
      COUNT(*) FILTER (WHERE status='selesai' AND tenggat IS NOT NULL)::numeric AS with_sla
    FROM p GROUP BY opd_id
  ), rate AS (
    SELECT p.opd_id, AVG(r.skor)::numeric AS r
    FROM public.permohonan_rating r JOIN public.permohonan p ON p.id = r.permohonan_id
    WHERE p.kategori = _kategori
    GROUP BY p.opd_id
  )
  SELECT o.id, o.nama, o.singkatan,
    COALESCE(a.total,0)::bigint,
    COALESCE(a.selesai,0)::bigint,
    CASE WHEN a.with_sla > 0 THEN ROUND(a.on_time / a.with_sla * 100, 2) ELSE NULL END,
    ROUND(COALESCE(rate.r,0)::numeric, 2),
    ROUND((COALESCE(a.selesai,0) + COALESCE(rate.r,0))::numeric, 2)
  FROM public.opd o
  LEFT JOIN agg a ON a.opd_id = o.id
  LEFT JOIN rate ON rate.opd_id = o.id
  ORDER BY 8 DESC;
$function$;
CREATE OR REPLACE FUNCTION public.opd_kinerja_agg()
 RETURNS TABLE(opd_id uuid, status text, total bigint, total_hari_selesai numeric, jumlah_selesai bigint, tepat_waktu bigint, selesai_dengan_sla bigint)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT p.opd_id, p.status::text, COUNT(*)::bigint,
    COALESCE(SUM(CASE WHEN p.status='selesai' AND p.tanggal_masuk IS NOT NULL AND p.updated_at IS NOT NULL
      THEN EXTRACT(EPOCH FROM (p.updated_at - p.tanggal_masuk))/86400.0 ELSE 0 END),0)::numeric,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tanggal_masuk IS NOT NULL AND p.updated_at IS NOT NULL)::bigint,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL AND p.updated_at <= p.tenggat)::bigint,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL)::bigint
  FROM public.permohonan p GROUP BY p.opd_id, p.status;
$function$;
CREATE OR REPLACE FUNCTION public.opd_kinerja_trend(_opd uuid DEFAULT NULL::uuid, _months integer DEFAULT 12)
 RETURNS TABLE(bulan text, masuk bigint, selesai bigint, on_time bigint, selesai_dengan_sla bigint)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT to_char(date_trunc('month', p.tanggal_masuk), 'YYYY-MM') AS bulan,
    COUNT(*)::bigint, COUNT(*) FILTER (WHERE p.status='selesai')::bigint,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL AND p.updated_at <= p.tenggat)::bigint,
    COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL)::bigint
  FROM public.permohonan p
  WHERE p.tanggal_masuk >= date_trunc('month', now()) - make_interval(months => GREATEST(_months,1))
    AND (_opd IS NULL OR p.opd_id = _opd)
  GROUP BY date_trunc('month', p.tanggal_masuk) ORDER BY 1;
$function$;
CREATE OR REPLACE FUNCTION public.opd_rating_agg()
 RETURNS TABLE(opd_id uuid, total_rating bigint, jumlah_rating bigint)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT p.opd_id, COALESCE(SUM(r.skor),0)::bigint, COUNT(r.id)::bigint
  FROM public.permohonan p JOIN public.permohonan_rating r ON r.permohonan_id = p.id
  WHERE p.opd_id IS NOT NULL GROUP BY p.opd_id;
$function$;
CREATE OR REPLACE FUNCTION public.opd_skor_komposit()
 RETURNS TABLE(opd_id uuid, opd_nama text, opd_singkatan text, kategori text[], total bigint, selesai bigint, sla_pct numeric, rating_avg numeric, completion_pct numeric, skor numeric)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  WITH agg AS (
    SELECT p.opd_id, COUNT(*)::bigint AS total,
      COUNT(*) FILTER (WHERE p.status='selesai')::numeric AS selesai,
      COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL AND p.updated_at <= p.tenggat)::numeric AS on_time,
      COUNT(*) FILTER (WHERE p.status='selesai' AND p.tenggat IS NOT NULL)::numeric AS with_sla
    FROM public.permohonan p GROUP BY p.opd_id
  ),
  rate AS (
    SELECT p.opd_id, AVG(r.skor)::numeric AS r
    FROM public.permohonan_rating r JOIN public.permohonan p ON p.id = r.permohonan_id
    GROUP BY p.opd_id
  )
  SELECT o.id, o.nama, o.singkatan, NULL::text[],
    COALESCE(a.total,0)::bigint, COALESCE(a.selesai,0)::bigint,
    CASE WHEN a.with_sla>0 THEN ROUND(a.on_time/a.with_sla*100,2) ELSE NULL END,
    ROUND(COALESCE(rate.r,0)::numeric,2),
    CASE WHEN a.total>0 THEN ROUND(a.selesai/a.total*100,2) ELSE NULL END,
    ROUND(COALESCE(
      0.5 * CASE WHEN a.total>0 THEN a.selesai/a.total*100 ELSE 0 END
      + 0.3 * CASE WHEN a.with_sla>0 THEN a.on_time/a.with_sla*100 ELSE 0 END
      + 0.2 * COALESCE(rate.r,0)*20, 0)::numeric, 2)
  FROM public.opd o LEFT JOIN agg a ON a.opd_id = o.id LEFT JOIN rate ON rate.opd_id = o.id
  ORDER BY 10 DESC;
$function$;
CREATE OR REPLACE FUNCTION public.prevent_self_role_change()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF auth.uid() IS NOT NULL AND NEW.user_id = auth.uid() THEN
    RAISE EXCEPTION 'Pengguna tidak diizinkan mengubah perannya sendiri';
  END IF;
  RETURN NEW;
END; $function$;
CREATE OR REPLACE FUNCTION public.production_health_score()
 RETURNS jsonb
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _cron_errors integer; _dead_letters integer; _overdue_perm integer; _score integer;
BEGIN
  IF NOT public.is_elevated_view(auth.uid()) THEN RAISE EXCEPTION 'Forbidden'; END IF;
  SELECT COUNT(*) INTO _cron_errors FROM public.cron_history
  WHERE status IN ('error','stalled') AND started_at >= now() - INTERVAL '24 hours';
  SELECT COUNT(*) INTO _dead_letters FROM public.dead_letter_jobs WHERE resolved_at IS NULL;
  SELECT COUNT(*) INTO _overdue_perm FROM public.v_permohonan_overdue;
  _score := GREATEST(0, 100 - LEAST(40, _cron_errors * 5) - LEAST(30, _dead_letters * 3) - LEAST(30, _overdue_perm * 2));
  RETURN jsonb_build_object('score', _score, 'cron_errors_24h', _cron_errors,
    'dead_letters', _dead_letters, 'overdue_permohonan', _overdue_perm,
    'level', CASE WHEN _score >= 90 THEN 'healthy' WHEN _score >= 70 THEN 'warning' ELSE 'critical' END,
    'generated_at', now());
END; $function$;
CREATE OR REPLACE FUNCTION public.rate_limit_increment(_scope text, _subject text, _window_start timestamp with time zone)
 RETURNS integer
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  _count integer;
BEGIN
  INSERT INTO public.rate_limit_hits (scope, subject, window_start, count, last_hit_at)
  VALUES (_scope, _subject, _window_start, 1, now())
  ON CONFLICT (scope, subject, window_start)
  DO UPDATE SET count = public.rate_limit_hits.count + 1, last_hit_at = now()
  RETURNING count INTO _count;
  RETURN _count;
END;
$function$;
CREATE OR REPLACE FUNCTION public.rating_list_admin()
 RETURNS TABLE(rating_id uuid, skor integer, komentar text, created_at timestamp with time zone, user_id uuid, pemohon_nama text, permohonan_id uuid, permohonan_kode text, permohonan_judul text, opd_id uuid, opd_singkatan text, opd_nama text)
 LANGUAGE sql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
  SELECT r.id, r.skor, r.komentar, r.created_at, r.user_id,
    pr.nama_lengkap, p.id, p.kode, p.judul, p.opd_id, o.singkatan, o.nama
  FROM public.permohonan_rating r
  LEFT JOIN public.permohonan p ON p.id = r.permohonan_id
  LEFT JOIN public.opd o ON o.id = p.opd_id
  LEFT JOIN public.profiles pr ON pr.id = r.user_id
  WHERE public.has_role(auth.uid(),'super_admin') ORDER BY r.created_at DESC;
$function$;
CREATE OR REPLACE FUNCTION public.riwayat_dengan_petugas(_permohonan_id uuid)
 RETURNS TABLE(id uuid, created_at timestamp with time zone, aksi text, catatan text, oleh uuid, nama_petugas text, email_petugas text)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE _opd uuid; _pemohon uuid;
BEGIN
  SELECT opd_id, pemohon_id INTO _opd, _pemohon FROM public.permohonan WHERE id = _permohonan_id;
  IF _opd IS NULL THEN RETURN; END IF;
  IF NOT (auth.uid() = _pemohon OR public.has_role(auth.uid(),'super_admin')
      OR (public.has_role(auth.uid(),'admin_opd') AND _opd = public.get_user_opd(auth.uid()))) THEN
    RAISE EXCEPTION 'Forbidden';
  END IF;
  RETURN QUERY
    SELECT r.id, r.created_at, r.aksi, r.catatan, r.oleh,
      COALESCE(p.nama_lengkap,''), COALESCE(u.email,'')
    FROM public.permohonan_riwayat r
    LEFT JOIN public.profiles p ON p.id = r.oleh
    LEFT JOIN auth.users u ON u.id = r.oleh
    WHERE r.permohonan_id = _permohonan_id ORDER BY r.created_at ASC;
END $function$;
CREATE OR REPLACE FUNCTION public.set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN NEW.updated_at = now(); RETURN NEW; END; $function$;
CREATE OR REPLACE FUNCTION public.sync_compliance_aliases()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.judul IS NULL THEN NEW.judul := NEW.label; END IF;
  IF NEW.label IS NULL THEN NEW.label := NEW.judul; END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.sync_dataset_review_aliases()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.aksi IS NULL THEN
    NEW.aksi := NEW.action;
  END IF;
  IF NEW.action IS NULL THEN
    NEW.action := NEW.aksi;
  END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.sync_dataset_submission_aliases()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.oleh_user_id IS NULL THEN
    NEW.oleh_user_id := NEW.user_id;
  END IF;
  IF NEW.user_id IS NULL THEN
    NEW.user_id := NEW.oleh_user_id;
  END IF;
  IF NEW.review_note IS NULL THEN
    NEW.review_note := NEW.catatan_review;
  END IF;
  IF NEW.catatan_review IS NULL THEN
    NEW.catatan_review := NEW.review_note;
  END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.sync_dataset_template_aliases()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.opd_pemilik_id IS NULL THEN
    NEW.opd_pemilik_id := NEW.opd_id;
  END IF;
  IF NEW.opd_id IS NULL THEN
    NEW.opd_id := NEW.opd_pemilik_id;
  END IF;
  IF NEW.kode IS NULL OR NEW.kode = '' THEN
    NEW.kode := 'DST-' || upper(substr(COALESCE(NEW.id, gen_random_uuid())::text, 1, 8));
  END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.sync_feature_flag_aliases()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.flag_key IS NULL THEN NEW.flag_key := NEW.key; END IF;
  IF NEW.key IS NULL THEN NEW.key := NEW.flag_key; END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.sync_uat_aliases()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.code IS NULL THEN NEW.code := upper(regexp_replace(COALESCE(NEW.modul, 'UAT') || '-' || substr(COALESCE(NEW.id, gen_random_uuid())::text, 1, 6), '[^A-Za-z0-9_-]', '-', 'g')); END IF;
  IF NEW.judul IS NULL THEN NEW.judul := NEW.description; END IF;
  IF NEW.expected IS NULL THEN NEW.expected := NEW.description; END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.tg_bump_version_number()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'UPDATE' THEN
    NEW.version_number := COALESCE(OLD.version_number, 0) + 1;
  END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.tg_pengajuan_izin_set_saldo_flag()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  IF TG_OP = 'INSERT' AND NEW.jenis = 'cuti_tahunan' AND NEW.mengurangi_saldo IS DISTINCT FROM true THEN
    NEW.mengurangi_saldo := true;
  END IF;
  RETURN NEW;
END;
$function$;
CREATE OR REPLACE FUNCTION public.tg_signed_documents_validate_revoke()
 RETURNS trigger
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  IF NEW.status = 'revoked' THEN
    IF NEW.revoke_reason IS NULL OR length(btrim(NEW.revoke_reason)) < 10 THEN
      RAISE EXCEPTION 'revoke_reason wajib diisi minimal 10 karakter';
    END IF;
    IF NEW.revoked_at IS NULL THEN
      NEW.revoked_at := now();
    END IF;
  END IF;
  RETURN NEW;
END $function$;

-- =====================  VIEWS  =====================
CREATE OR REPLACE VIEW public.aset_nilai_buku AS
 SELECT id,
    kode,
    nama,
    opd_id,
    nilai_perolehan,
    tanggal_perolehan,
    umur_ekonomis_bulan,
    metode_susut,
    GREATEST((COALESCE(nilai_perolehan, (0)::numeric) - COALESCE(( SELECT h.akumulasi
           FROM aset_penyusutan_history h
          WHERE (h.aset_id = a.id)
          ORDER BY h.periode DESC, h.created_at DESC
         LIMIT 1), (0)::numeric)), COALESCE(nilai_sisa, (0)::numeric)) AS nilai_buku
   FROM aset a;
CREATE OR REPLACE VIEW public.v_permohonan_overdue AS
 SELECT id,
    kode,
    opd_id,
    (GREATEST((0)::numeric, ceil((EXTRACT(epoch FROM (now() - tenggat)) / 86400.0))))::integer AS overdue_days,
    (status)::text AS status
   FROM permohonan p
  WHERE ((tenggat IS NOT NULL) AND (tenggat < now()) AND ((status)::text <> ALL (ARRAY['selesai'::text, 'ditolak'::text])));

-- =====================  TRIGGERS  =====================
DROP TRIGGER IF EXISTS trg_app_setting_updated_at ON public.app_setting;
CREATE TRIGGER trg_app_setting_updated_at BEFORE UPDATE ON public.app_setting FOR EACH ROW EXECUTE FUNCTION set_updated_at();
DROP TRIGGER IF EXISTS aset_updated_at ON public.aset;
CREATE TRIGGER aset_updated_at BEFORE UPDATE ON public.aset FOR EACH ROW EXECUTE FUNCTION set_updated_at();
DROP TRIGGER IF EXISTS trg_aset_bump_version ON public.aset;
CREATE TRIGGER trg_aset_bump_version BEFORE UPDATE ON public.aset FOR EACH ROW EXECUTE FUNCTION tg_bump_version_number();
DROP TRIGGER IF EXISTS trg_berita_updated ON public.berita;
CREATE TRIGGER trg_berita_updated BEFORE UPDATE ON public.berita FOR EACH ROW EXECUTE FUNCTION set_updated_at();
DROP TRIGGER IF EXISTS trg_sync_compliance_aliases ON public.compliance_checklist;
CREATE TRIGGER trg_sync_compliance_aliases BEFORE INSERT OR UPDATE ON public.compliance_checklist FOR EACH ROW EXECUTE FUNCTION sync_compliance_aliases();
DROP TRIGGER IF EXISTS trg_data_terpadu_updated_at ON public.data_terpadu_item;
CREATE TRIGGER trg_data_terpadu_updated_at BEFORE UPDATE ON public.data_terpadu_item FOR EACH ROW EXECUTE FUNCTION set_updated_at();
